## 🧩 **2. Middleware для внедрения ID аудиокниги в контекст запроса**

**Путь:** `./src/middlewares/audiobook-id.js`

```js
module.exports = (config, { strapi }) => {
  return async (ctx, next) => {
    if (ctx.request.url.startsWith('/api/upload')) {
      const audiobookId = ctx.request.query.audiobookId;

      if (!audiobookId || isNaN(audiobookId)) {
        return ctx.throw(400, 'Invalid audiobook ID');
      }

      const audiobook = await strapi.db.query('api::audiobook.audiobook').findOne({ where: { id: audiobookId } });
      if (!audiobook) {
        return ctx.throw(404, `Audiobook with ID ${audiobookId} not found`);
      }

      if (ctx.request.files) {
        ctx.request.files = ctx.request.files.map(file => {
          file.related = { id: audiobookId };
          return file;
        });
      }
    }

    await next();
  };
};
```

**Добавьте middleware в `config/middlewares.js`:**
```js
module.exports = [
  // ...
  'global::audiobook-id',
];
```

