## 📥 **3. Контроллер для пользовательской загрузки**

**Путь:** `./src/api/audiobook/controllers/upload.js`

```js
module.exports = {
  async upload(ctx) {
    const { id } = ctx.params;
    const files = ctx.request.files;

    const audiobook = await strapi.db.query('api::audiobook.audiobook').findOne({ where: { id } });
    if (!audiobook) return ctx.throw(404, `Audiobook with ID ${id} not found`);

    const user = ctx.state.user;
    if (user.id !== audiobook.author.id) {
      return ctx.throw(403, 'You do not have permission to upload files for this audiobook');
    }

    files.forEach(file => {
      file.related = { id };
    });

    const uploadService = strapi.plugins.upload.services.upload;
    const response = await uploadService.upload({ data: {}, files });

    await strapi.db.query('api::audiobook.audiobook').update({
      where: { id },
      data: {
        files: [...(audiobook.files || []), ...response.map(f => f.url)],
      },
    });

    return response;
  },
};
```

